use bytes::Bytes;
use slatedb::{object_store::memory::InMemory, Db};
use std::ops::Bound;
use std::sync::Arc;

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    let db = Db::open("/tmp/slatedb-empty-range-repro-db", Arc::new(InMemory::new())).await?;
    db.put(b"a", b"one").await?;
    db.put(b"b", b"two").await?;

    assert_first_key(&db, Bytes::new().., Some(b"a")).await?;
    assert_first_key(
        &db,
        (Bound::Excluded(Bytes::new()), Bound::Unbounded),
        Some(b"a"),
    )
    .await?;
    assert_first_key(&db, Bytes::new()..Bytes::from_static(b"b"), Some(b"a")).await?;
    assert_first_key(&db, ..Bytes::new(), None).await?;
    assert_first_key(&db, ..=Bytes::new(), None).await?;
    assert_first_key(&db, Bytes::new()..=Bytes::new(), None).await?;

    db.close().await?;
    Ok(())
}

async fn assert_first_key<K, T>(
    db: &Db,
    range: T,
    expected: Option<&[u8]>,
) -> Result<(), Box<dyn std::error::Error>>
