    K: AsRef<[u8]> + Send,
    T: std::ops::RangeBounds<K> + Send,
{
    let mut iter = db.scan::<K, T>(range).await?;
    let actual = iter.next().await?.map(|entry| entry.key);
    assert_eq!(actual.as_deref(), expected);
    Ok(())
}
